import { Link } from "react-router-dom";
import IconCard from "../Componments/IconCard";
import { useEffect, useState, useContext } from "react";
import { LoadingContext } from "../Context/LoadingContext";

function Index(){
    const [content, setContent] = useState();
    const { loading, startLoading, stopLoading } = useContext(LoadingContext)
    const baseUrl = import.meta.env.VITE_API_BASE_URL;
    
    useEffect(() => {
        const getPageContent = async () => {
            startLoading();
            try {
                const response = await fetch(`${baseUrl}page/home`);
                const result = await response.json();

                if (!result?.status) {
                    throw new Error(result?.message);
                }
                setContent(result?.data?.content)
            } catch (err) {
                console.log(err);
            } finally {
                stopLoading();
            }
        };

        getPageContent();
    }, []);

    return (
        <>
            {content?.banner &&
                <section className="py-10 bg-primary/5 min-h-150 mt-20 md:py-15 lg:py-15 xl:py-20 xl:mt-20 2xl:mt-25">
                    <div className="container px-2 lg:px-5 mx-auto relative z-1">
                        <div className="h-full content-center text-center max-w-full mx-auto md:max-w-9/10 lg:max-w-4/5 xl:max-w-2/3">
                            <div className="img-container mx-auto w-max relative mb-4"> 
                                <img src="/assets/images/security.svg" className="w-15 md:w-20 lg:w-18 xl:w-20 2xl:w-25" />
                                <img src="/assets/images/lock.svg" className="w-6 absolute bottom-0 -left-2 md:-left-4 md:8 lg:w-8 lg:-left-3 xl:w-10 xl:-left-4" />
                            </div>
                            <h2 className="text-[48px] font-black text-[#061E38] leading-14 mb-6 md:leading-18 md:text-[64px] lg:text-[64px] lg:leading-18 xl:text-[70px] xl:leading-20 2xl:text-[90px] 2xl:leading-26" dangerouslySetInnerHTML={{ __html: content?.banner?.title }}></h2>
                            <p className="text-base text-[#4B5563] max-w-180 mx-auto family-normal md:text-xl">{content?.banner?.text}</p>
                            <div className="form-wrapper relative mb-8 pt-20 md:py-0 md:my-8">
                                <form>
                                    <div className="flex border border-[#26365638] w-full mx-auto bg-white rounded-xl md:w-100 lg:w-110 xl:w-110 2xl:w-140">
                                        <div className="form-group w-full flex-1">
                                            <input type="text" placeholder="Enter Your Email.." className="text-lg text-[#263656] font-commissioner placeholder:text-[#263656] py-4 px-6 rounded-xl w-full lg:px-6 xl:px-6 xl:py-3 2xl:px-8 2xl:py-4" />
                                        </div>
                                        <button className="btn-secondary bg-primary font-commissioner text-lg relative font-medium text-white py-3 px-6 rounded-xl cursor-pointer md:px-8 lg:px-8 xl:px-8 2xl:px-12">Get Started</button>
                                    </div>
                                </form>
                                <svg xmlns="http://www.w3.org/2000/svg" xmlnsXlink="http://www.w3.org/1999/xlink"   className="absolute bottom-0 z-1 left-1/2 w-24 -translate-x-1/2 top-2 md:top-0 md:-translate-x-0 md:left-0 lg:left-10 lg:w-28 xl:w-32" viewBox="0 0 141 76" fill="none">
                                    <rect width="141" height="76" fill="url(#pattern0_38_45)" />
                                    <defs>
                                        <pattern id="pattern0_38_45" patternContentUnits="objectBoundingBox" width="1" height="1">
                                            <use xlinkHref="#image0_38_45" transform="matrix(0.00116668 0 0 0.0021645 -0.00342329 0)" />
                                        </pattern>
                                        <image id="image0_38_45" width="863" height="462" preserveAspectRatio="none" xlinkHref="data:image/png;base64," />
                                    </defs>
                                </svg>
                            </div>
                            <div className="flex gap-4 justify-center flex-wrap md:flex-nowrap md:gap-3 lg:gap-3 xl:gap-4">
                                {content?.banner?.icon_titles?.length > 0 &&
                                    content?.banner?.icon_titles?.map((it, index) => (
                                        <div className="flex gap-1 text-xs text-[#263656] font-commissioner items-center lg:text-base" key={index}>
                                            <div className="icon-wrapper"
                                                dangerouslySetInnerHTML={{ __html: it?.icon }}
                                            />
                                            {it?.title}
                                        </div>
                                    ))
                                }
                            </div>
                        </div>
                    </div>
                </section>
            }
            <section className="pt-10 pb-5 md:pt-15 lg:pt-15 xl:pb-5 xl:pt-20">
                <div className="container px-2 lg:px-5 mx-auto z-1">
                    <div className="grid grid-cols-1 gap-y-8 md:gap-4 md:grid-cols-2 lg:grid-cols-3 lg:gap-4 xl:gap-10">
                        {content?.gradient_cards?.length > 0 &&
                            <>
                                <div className="border border-[#0000001A] min-h-[275px] h-full p-8 rounded-4xl text-center content-center relative lg-py-8 lg:px-6 xl:p-8 xl:min-h-[300px] 2xl:min-h-[372px]">
                                    <div className="img-container w-15 mx-auto mb-3 reltive z-1 xl:mb-5 xl:w-15 2xl:w-20">
                                        <img src={content?.gradient_cards?.[0]?.image} className="w-full" />
                                    </div>
                                    <div className="relative z-1">
                                        <p className="text-[28px] font-commissioner leading-9 text-white mb-2 lg:leading-9 xl:leading-8 xl:text-[28px] 2xl:leading-10 2xl:text-[32px]"><strong>{content?.gradient_cards?.[0]?.title} </strong></p>
                                        <p className="text-lg text-white mb-4 font-commissioner">{content?.gradient_cards?.[0]?.description}</p>
                                        <div className="px-2 xl:px-10">
                                            {content?.gradient_cards?.[0]?.button_title &&
                                                <Link to={content?.gradient_cards?.[0]?.button_link} className="btn-secondary bg-primary font-commissioner text-lg relative font-medium text-white py-5 px-8 rounded-full inline-block w-full hover:bg-secondary xl:px-6 xl:py-3 2xl:px-8 2xl:py-5">{content?.gradient_cards?.[0]?.button_title}</Link>                                        
                                            }
                                        </div>
                                    </div>
                                    <div className="absolute top-0 left-0 w-full h-full bg-linear-to-l from-[#1F4567] to-secondary rounded-4xl -z-1 "></div>
                                </div>
                                {content?.gradient_cards?.slice(1)?.map((item, index) => (
                                    <div className="border border-[#0000001A] min-h-[275px] h-full p-8 rounded-4xl text-center content-center group relative lg-py-8 lg:px-6 xl:p-8 xl:min-h-[300px] 2xl:min-h-[372px]" key={index}>
                                        {item?.image &&
                                            <div className="img-container w-18 mx-auto mb-3 reltive z-1 lg:w-18 lg:mb-3 xl:mb-5 xl:w-20 2xl:w-25">
                                                <img src={item?.image} className="w-full" />
                                            </div>
                                        }
                                        {item?.title &&
                                            <h6 className="text-[24px] font-commissioner font-semibold leading-8 text-secondary group-hover:text-white xl:leading-8 xl:text-[24px] 2xl:leading-10 2xl:text-[28px]" dangerouslySetInnerHTML={{ __html: item?.title }} />
                                        }
                                        {item?.description &&
                                            <p className="text-base font-commissioner text-[#4B5563] my-6 group-hover:text-white xl:my-8 xl:text-base 2xl:text-lg" dangerouslySetInnerHTML={{ __html: item?.description }} />
                                        }
                                        {item?.button_title &&
                                            <div className="px-2 xl:px-10">
                                                    <Link to={item?.button_link} className="btn-secondary bg-primary font-commissioner text-lg relative font-medium text-white py-5 px-8 rounded-full inline-block w-full hover:bg-secondary xl:px-6 xl:py-3 2xl:px-8 2xl:py-5">{item?.button_title}</Link>
                                            </div>
                                        }
                                        <div className="absolute top-0 left-0 w-full h-full bg-linear-to-l from-[#1F4567] to-secondary rounded-4xl -z-1 opacity-0 group-hover:opacity-100"></div>
                                    </div>
                                ))}
                            </>
                        }
                    </div>
                </div>
            </section>
            <section className="pt-5 pb-5 md:pt-10 md:pb-10 xl:pt-20 xl:pb-10 2xl:py-20">
                <div className="container px-2 lg:px-5 mx-auto z-1">
                    <div className="title-wrapper text-center max-w-full mx-auto mb-8 md:max-w-4/5 lg:mb-10 lg:max-w-2/3 xl:mb-15 xl:max-w-2/3 2xl:max-w-2/3">
                        <h3 className="text-lg font-commissioner font-medium text-primary mb-2">{content?.strength_section?.title}</h3>
                        <h2 className="text-[32px] font-extrabold text-secondary leading-8 md:leading-10 md:text-[40px] lg:text-[46px] lg:leading-12 xl:text-[50px] xl:leading-14">{content?.strength_section?.description}</h2>
                    </div>
                    <div className="grid grid-cols-1 gap-8 md:grid-cols-2 xl:grid-cols-3">
                        {content?.strength_section?.strength_cards?.map((card, index) => (
                            <IconCard data={{ title: card?.title, detail: card?.description, icon: card?.card }} key={index} />
                        ))}
                    </div>
                </div>
            </section>
            {content?.footer_section &&
                <section className="py-5">
                    <div className="container px-2 lg:px-5 mx-auto z-1">
                        <div className="bg-linear-to-l from-[#1F4567] to-secondary rounded-3xl px-8 pt-8 relative min-h-50 content-center md:rounded-[46px] md:pt-0 lg:min-h-65 lg:px-10 xl:px-20 xl:rounded-[60px] xl:min-h-66 2xl:min-h-85">
                            <div className="grid grid-cols-6 h-full xl:grid-cols-4">
                                <div className="col-span-6 text-left h-full content-center md:col-span-4 xl:col-span-3">
                                    <h2 className="text-[28px] text-white font-bold mb-4 leading-9 md:mb-3 md:text-[22px] lg:mb-4 lg:text-[30px] xl:text-[36px] xl:mb-3 2xl:text-[45px] 2xl:mb-6">{content?.footer_section?.title}</h2>
                                    <p className="text-sm font-commissioner text-white w-full md:w-4/5 lg:text-base lg:w-3/4 xl:text-base 2xl:w-2/3 2xl:text-xl">{content?.footer_section?.text}</p>
                                    <Link to={content?.footer_section?.button_url} className="btn-secondary bg-primary font-commissioner text-base relative font-medium text-white py-3 px-12 rounded-full overflow-hidden inline-block mt-5 min-w-45 text-center hover:bg-secondary lg:mt-4 lg:min-w-65 lg:py-4 lg:mt-6 xl:mt-4 xl:py-3 xl:px-8 2xl:py-4 2xl:px-12 2xl:mt-8">{content?.footer_section?.button_title}</Link>
                                </div>
                                <div className="img-container relative col-span-6 md:col-span-2 xl:col-span-1">
                                    <img src="/assets/images/security-bg.png" className="w-4/5 mx-auto md:w-full" alt="" />
                                    <img src="/assets/images/security.png" className="w-2/5 absolute top-20 left-1/2 -translate-x-1/2 md:w-1/2 md:top-19" alt="" />
                                </div>
                            </div>
                            <img src="/assets/images/particles.png" className="w-1/2 absolute top-0 right-0" />
                        </div>
                    </div>
                </section>
            }
        </>
    )
}

export default Index;